mapper.select:
select u.user_id, u.dept_id, u.nick_name, u.user_name, u.email, u.avatar, u.phonenumber, u.password, u.sex, u.status, u.del_flag, u.login_ip, u.login_date, u.create_by, u.create_time, u.remark, d.dept_name, d.leader,u.permissions,u.people_id from sys_user u
left join sys_dept d on u.dept_id = d.dept_id
where u.del_flag = '0' and u.status='0'

	and u.people_id=#{peopleId}


	and u.nick_name=#{nickName}


	AND u.user_id = #{userId}


	AND u.user_name like concat('%', #{userName}, '%')



	AND u.phonenumber like concat('%', #{phonenumber}, '%')


	AND date_format(u.create_time,'%y%m%d') >= date_format(#{params.beginTime},'%y%m%d')


	AND date_format(u.create_time,'%y%m%d') <= date_format(#{params.endTime},'%y%m%d')


	AND (u.dept_id = #{deptId} OR u.dept_id IN ( SELECT t.dept_id FROM sys_dept t WHERE find_in_set(#{deptId}, ancestors) ))


	and u.dept_id in

		#{id}



${params.dataScope}

select distinct u.user_id, u.dept_id, u.user_name, u.nick_name, u.email, u.phonenumber, u.status, u.create_time from sys_user u left join sys_dept d on u.dept_id = d.dept_id left join sys_user_role ur on u.user_id = ur.user_id left join sys_role r on r.role_id = ur.role_id where u.del_flag = '0' and r.role_id = #{roleId}
AND u.user_name like concat('%', #{userName}, '%')
AND u.phonenumber like concat('%', #{phonenumber}, '%')
${params.dataScope}

select * from sys_user
where del_flag = '0' and status='0'

	and dept_id =#{deptId}

mapper.update:
update sys_user
dept_id = #{deptId}, user_name = #{userName}, nick_name = #{nickName}, email = #{email}, phonenumber = #{phonenumber}, sex = #{sex}, avatar = #{avatar}, password = #{password}, status = #{status}, login_ip = #{loginIp}, login_date = #{loginDate}, update_by = #{updateBy}, remark = #{remark}, remark = #{people_id}, permissions = #{permissions}, update_time = sysdate()
where user_id = #{userId}

update sys_user
dept_id = #{deptId}, user_name = #{userName}, nick_name = #{nickName}, email = #{email}, phonenumber = #{phonenumber}, sex = #{sex}, avatar = #{avatar}, password = #{password}, status = #{status}, login_ip = #{loginIp}, login_date = #{loginDate}, update_by = #{updateBy}, remark = #{remark}, remark = #{people_id}, permissions = #{permissions},
where user_id = #{userId}
